{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://kapow.dev/schemas/product-contract.schema.json",
  "title": "Product Contract",
  "description": "Schema for product-facing contracts that define user-visible features, pages, integrations, and data-quality promises.",
  "type": "object",
  "required": ["id", "title", "description", "status", "owner", "category"],
  "additionalProperties": false,
  "properties": {
    "id": {
      "type": "string",
      "pattern": "^[a-z0-9]+(-[a-z0-9]+)*$",
      "description": "Unique identifier in kebab-case (e.g., 'institution-search')."
    },
    "title": {
      "type": "string",
      "minLength": 1,
      "description": "Human-readable name of the contract."
    },
    "description": {
      "type": "string",
      "minLength": 1,
      "description": "What this contract promises to users."
    },
    "status": {
      "type": "string",
      "enum": ["shipped", "experimental", "planned", "deprecated"],
      "description": "Current lifecycle status."
    },
    "owner": {
      "type": "string",
      "minLength": 1,
      "description": "Team or person responsible for this contract."
    },
    "category": {
      "type": "string",
      "enum": ["feature", "page", "integration", "data-quality"],
      "description": "Type of product contract."
    },
    "user_story": {
      "type": "string",
      "description": "User story in 'As a ... I can ...' format."
    },
    "acceptance_criteria": {
      "type": "array",
      "items": { "type": "string" },
      "description": "Conditions that must be true for this contract to be considered fulfilled."
    },
    "source_files": {
      "type": "array",
      "items": { "type": "string" },
      "description": "File paths (relative to repo root) that implement this contract."
    },
    "tests": {
      "type": "array",
      "items": { "type": "string" },
      "description": "Test file paths or test name patterns that verify this contract."
    },
    "issues": {
      "type": "array",
      "items": {
        "type": "string",
        "pattern": "^kapow-[a-z0-9]+",
        "description": "Beads issue ID."
      },
      "description": "Linked beads issue IDs."
    },
    "evidence": {
      "type": "object",
      "required": ["type"],
      "additionalProperties": false,
      "properties": {
        "type": {
          "type": "string",
          "enum": ["test", "manual", "monitoring", "assertion"],
          "description": "How the contract claim is verified."
        },
        "description": {
          "type": "string",
          "description": "Details about the verification method."
        },
        "references": {
          "type": "array",
          "items": { "type": "string" },
          "description": "Links to test runs, dashboards, or other proof."
        }
      },
      "description": "How this contract is verified."
    },
    "created": {
      "type": "string",
      "format": "date",
      "description": "Date the contract was created (YYYY-MM-DD)."
    },
    "updated": {
      "type": "string",
      "format": "date",
      "description": "Date the contract was last updated (YYYY-MM-DD)."
    }
  }
}

